```python
from enum import EnumMeta, StrEnum, auto, unique
from dataclasses import dataclass

class ColumnEnumMeta(EnumMeta):
    def __new__(mcls, name, bases, namespace, **kwargs):
        # Create the class first
        cls = super().__new__(mcls, name, bases, namespace, **kwargs)

        # Then modify the auto-generated values
        for member in cls:
            if member._value_ is None:  # This is an auto() member
                member._value_ = f"{name}____{member.name.upper()}"
        return cls

@unique
class ColumnEnum(StrEnum, metaclass=ColumnEnumMeta):
    def __repr__(self) -> str:
        return self.value

