def numba_jv(v, x):
    return np.float64(sp.jv(v, x))

@jit(nopython=True)
def numba_struve(v, x):
    return np.float64(sp.struve(v, x))

@jit(nopython=True)
def Grh_gtr(J2, t1, t2):
    t = t1 - t2
    if t == 0:
        return -1j/2
    else:
        J2t = J2 * t
        return (numba_jv(1, J2t) - 1j * numba_struve(1, J2t)) / (2j * J2t)
```

